using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API (JSONPlaceholder) using HttpClient.
/// Uses constructor injection — the SDK resolves DI services automatically
/// and keeps them out of the tool schema exposed to LLMs.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List posts from the API. Optionally filter by user ID.")]
    public async Task<string> ListPosts(
        [Description("User ID to filter posts by. Omit to list all posts.")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"posts?userId={userId}" : "posts";
        logger.LogInformation("Listing posts: {Url}", url);

        var posts = await httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);
        return JsonSerializer.Serialize(posts, JsonOptions);
    }

    [McpServerTool, Description("Get a single post by its ID.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post to retrieve.")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting post {PostId}", postId);

        var response = await httpClient.GetAsync($"posts/{postId}", cancellationToken);
        if (!response.IsSuccessStatusCode)
        {
            return $"Error: post {postId} not found (HTTP {(int)response.StatusCode}).";
        }

        var post = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(post, JsonOptions);
    }

    [McpServerTool, Description("Get comments for a specific post.")]
    public async Task<string> GetPostComments(
        [Description("The post ID to retrieve comments for.")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting comments for post {PostId}", postId);

        var comments = await httpClient.GetFromJsonAsync<JsonElement>(
            $"posts/{postId}/comments", cancellationToken);
        return JsonSerializer.Serialize(comments, JsonOptions);
    }

    [McpServerTool(Destructive = false, ReadOnly = true),
     Description("Search posts whose title or body contains the given query text.")]
    public async Task<string> SearchPosts(
        [Description("Text to search for in post titles and bodies.")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching posts for '{Query}'", query);

        var posts = await httpClient.GetFromJsonAsync<JsonElement[]>("posts", cancellationToken)
            ?? [];

        var matches = posts.Where(p =>
            (p.GetProperty("title").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) ?? false) ||
            (p.GetProperty("body").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) ?? false));

        return JsonSerializer.Serialize(matches, JsonOptions);
    }
}

